      out.write("                <div id=\"google_translate_element\" style=\"display:none\"></div>\r\n");
      out.write("                <script type=\"text/javascript\">\r\n");
      out.write("                    function setCookie(key, value, expiry) {\r\n");
      out.write("                        var expires = new Date();\r\n");
      out.write("                        expires.setTime(expires.getTime() + (expiry * 24 * 60 * 60 * 1000));\r\n");
      out.write("                        document.cookie = key + '=' + value + ';expires=' + expires.toUTCString() + ';path=/';\r\n");
      out.write("                    }\r\n");
      out.write("\r\n");
      out.write("                    function getCookie(key) {\r\n");
      out.write("                        var name = key + \"=\";\r\n");
      out.write("                        var decodedCookie = decodeURIComponent(document.cookie);\r\n");
      out.write("                        var ca = decodedCookie.split(';');\r\n");
      out.write("                        for (var i = 0; i < ca.length; i++) {\r\n");
      out.write("                            var c = ca[i];\r\n");
      out.write("                            while (c.charAt(0) == ' ') {\r\n");
      out.write("                                c = c.substring(1);\r\n");
      out.write("                            }\r\n");
      out.write("                            if (c.indexOf(name) == 0) {\r\n");
      out.write("                                return c.substring(name.length, c.length);\r\n");
      out.write("                            }\r\n");
      out.write("                        }\r\n");
      out.write("                        return \"\";\r\n");
      out.write("                    }\r\n");
      out.write("\r\n");
      out.write("                    function googleTranslateElementInit() {\r\n");
      out.write("                        new google.translate.TranslateElement({\r\n");
      out.write("                            pageLanguage: 'en',\r\n");
      out.write("                            includedLanguages: 'en,kn',\r\n");
      out.write("                            layout: google.translate.TranslateElement.InlineLayout.SIMPLE,\r\n");
      out.write("                            autoDisplay: true\r\n");
      out.write("                        }, 'google_translate_element');\r\n");
      out.write("\r\n");
      out.write("                        // Persistent Language Logic\r\n");
      out.write("                        var preferredLang = localStorage.getItem('preferredLanguage') || getCookie('selectedLang');\r\n");
      out.write("                        if (preferredLang && preferredLang !== 'en') {\r\n");
      out.write("                            var checkExist = setInterval(function () {\r\n");
      out.write("                                var select = document.querySelector('select.goog-te-combo');\r\n");
      out.write("                                if (select) {\r\n");
      out.write("                                    if (select.value !== preferredLang) {\r\n");
      out.write("                                        translateLanguage(preferredLang);\r\n");
      out.write("                                    }\r\n");
      out.write("                                    clearInterval(checkExist);\r\n");
      out.write("                                }\r\n");
      out.write("                            }, 100);\r\n");
      out.write("                            setTimeout(function () { clearInterval(checkExist); }, 8000);\r\n");
      out.write("                        }\r\n");
      out.write("                    }\r\n");
      out.write("\r\n");
      out.write("                    function translateLanguage(langCode) {\r\n");
      out.write("                        var select = document.querySelector('select.goog-te-combo');\r\n");
      out.write("\r\n");
      out.write("                        // Update persistence\r\n");
      out.write("                        localStorage.setItem('preferredLanguage', langCode);\r\n");
      out.write("                        setCookie('selectedLang', langCode, 7);\r\n");
      out.write("                        setCookie('googtrans', '/en/' + langCode, 7);\r\n");
      out.write("\r\n");
      out.write("                        // Update UI Label\r\n");
      out.write("                        var label = document.getElementById('currentLangLabel');\r\n");
      out.write("                        if (label) {\r\n");
      out.write("                            label.innerText = (langCode === 'kn') ? 'ಕನ್ನಡ' : 'English';\r\n");
      out.write("                        }\r\n");
      out.write("\r\n");
      out.write("                        if (select) {\r\n");
      out.write("                            select.value = langCode;\r\n");
      out.write("                            select.dispatchEvent(new Event('change'));\r\n");
      out.write("                        } else {\r\n");
      out.write("                            // Retry once if widget not loaded\r\n");
      out.write("                            setTimeout(function () {\r\n");
      out.write("                                var selectRetry = document.querySelector('select.goog-te-combo');\r\n");
      out.write("                                if (selectRetry) {\r\n");
      out.write("                                    selectRetry.value = langCode;\r\n");
      out.write("                                    selectRetry.dispatchEvent(new Event('change'));\r\n");
      out.write("                                }\r\n");
      out.write("                            }, 800);\r\n");
      out.write("                        }\r\n");
      out.write("                    }\r\n");
      out.write("\r\n");
      out.write("                    // Initial Label Setup\r\n");
      out.write("                    document.addEventListener('DOMContentLoaded', function () {\r\n");
      out.write("                        var preferredLang = localStorage.getItem('preferredLanguage') || getCookie('selectedLang');\r\n");
      out.write("                        var label = document.getElementById('currentLangLabel');\r\n");
      out.write("                        if (preferredLang === 'kn' && label) {\r\n");
      out.write("                            label.innerText = 'ಕನ್ನಡ';\r\n");
      out.write("                        }\r\n");
      out.write("                    });\r\n");
      out.write("                </script>\r\n");
      out.write("                <script type=\"text/javascript\"\r\n");
